const en: ToolDict = {};

export const TOOL_DICTS: Partial<Record<Locale, ToolDict>> = {
  en, ko, ja, 'zh-CN': zhCN,
};

export function getToolDict(locale: Locale): ToolDict {
  return TOOL_DICTS[locale] ?? {};
}

export function getToolContent(locale: Locale, tool: ToolKey): ToolPageContent | undefined {
  return TOOL_DICTS[locale]?.[tool];
}
